export default {
  id: 98,
  title: 'Практикум: Паттерны проектирования',
  description: 'Реализация паттернов проектирования в идиоматическом стиле Go: Singleton, Factory, Builder, Observer, Strategy, Decorator, Adapter, Command, Iterator и Chain of Responsibility.',
  lessons: [
    {
      id: 1,
      title: 'Singleton (Одиночка)',
      type: 'practice',
      difficulty: 'easy',
      description: 'Реализуй паттерн Singleton для конфигурации приложения и подключения к базе данных. Обеспечь потокобезопасность.',
      requirements: [
        'Singleton для AppConfig: хранит настройки приложения',
        'Используй sync.Once для потокобезопасной инициализации',
        'Метод GetConfig() *AppConfig — возвращает единственный экземпляр',
        'Поддержи обновление конфигурации через UpdateConfig(key, value string)',
        'Протестируй конкурентный доступ: 10 горутин получают конфиг одновременно, проверь что это один и тот же объект'
      ],
      expectedOutput: 'Все 10 горутин получили один и тот же экземпляр: true\nConfig addr одинаковый: true\nDebug: true\nPort: 9090',
      hint: 'var instance *AppConfig; var once sync.Once. GetConfig() { once.Do(func() { instance = &AppConfig{...} }); return instance }. sync.Once гарантирует однократное выполнение Do даже при конкурентных вызовах.',
      solution: 'package main\n\nimport (\n    "fmt"\n    "sync"\n)\n\ntype AppConfig struct {\n    mu     sync.RWMutex\n    values map[string]string\n}\n\nvar (\n    configInstance *AppConfig\n    configOnce    sync.Once\n)\n\nfunc GetConfig() *AppConfig {\n    configOnce.Do(func() {\n        configInstance = &AppConfig{\n            values: map[string]string{\n                "host":  "localhost",\n                "port":  "8080",\n                "debug": "false",\n            },\n        }\n    })\n    return configInstance\n}\n\nfunc (c *AppConfig) Get(key string) string {\n    c.mu.RLock()\n    defer c.mu.RUnlock()\n    return c.values[key]\n}\n\nfunc (c *AppConfig) Set(key, value string) {\n    c.mu.Lock()\n    defer c.mu.Unlock()\n    c.values[key] = value\n}\n\nfunc main() {\n    var wg sync.WaitGroup\n    configs := make([]*AppConfig, 10)\n    for i := 0; i < 10; i++ {\n        wg.Add(1)\n        go func(idx int) {\n            defer wg.Done()\n            configs[idx] = GetConfig()\n        }(i)\n    }\n    wg.Wait()\n    allSame := true\n    for _, c := range configs {\n        if c != configs[0] {\n            allSame = false\n        }\n    }\n    fmt.Printf("Все 10 горутин получили один и тот же экземпляр: %v\\n", allSame)\n    fmt.Printf("Config addr одинаковый: %v\\n", configs[0] == configs[9])\n    cfg := GetConfig()\n    cfg.Set("debug", "true")\n    cfg.Set("port", "9090")\n    fmt.Printf("Debug: %s\\n", GetConfig().Get("debug"))\n    fmt.Printf("Port: %s\\n", GetConfig().Get("port"))\n}',
      explanation: 'sync.Once гарантирует однократное выполнение функции в Do, независимо от количества конкурентных вызовов. Это предпочтительнее мьютекса с проверкой instance==nil (double-checked locking) — в Go нет гарантий порядка операций записи без синхронизации. AppConfig дополнительно защищён RWMutex для безопасных конкурентных операций Get/Set.'
    },
    {
      id: 2,
      title: 'Factory (Фабрика)',
      type: 'practice',
      difficulty: 'easy',
      description: 'Реализуй паттерн Factory Method и Abstract Factory для создания различных типов уведомлений и транспортов.',
      requirements: [
        'Интерфейс Notifier: Send(to, subject, body string) error',
        'Реализации: EmailNotifier, SMSNotifier, PushNotifier',
        'NotifierFactory(notifierType string) (Notifier, error) — простая фабрика',
        'Интерфейс NotificationFactory с методами CreateNotifier() Notifier, CreateLogger() Logger',
        'Реализации AbstractFactory: DevelopmentFactory (stdout notifier), ProductionFactory (реальные сервисы)'
      ],
      expectedOutput: 'EmailNotifier.Send: [EMAIL] to: alice@example.com subject: Привет\nSMSNotifier.Send: [SMS] to: +77001234567 message: Код: 1234\nPushNotifier.Send: [PUSH] device: device123 title: Уведомление\nDevelopment Factory: отправка в stdout\nProduction Factory: отправка через внешние сервисы',
      hint: 'Factory function возвращает интерфейс, скрывая конкретную реализацию. В Go принято использовать конструкторы типа New...(). Abstract Factory: интерфейс фабрики, две конкретные реализации.',
      solution: 'package main\n\nimport (\n    "fmt"\n    "strings"\n)\n\ntype Notifier interface {\n    Send(to, subject, body string) error\n}\n\ntype Logger interface {\n    Log(level, message string)\n}\n\ntype EmailNotifier struct{ From string }\nfunc (n *EmailNotifier) Send(to, subject, body string) error {\n    fmt.Printf("[EMAIL] from: %s to: %s subject: %s\\n  body: %s\\n", n.From, to, subject, body)\n    return nil\n}\n\ntype SMSNotifier struct{ Provider string }\nfunc (n *SMSNotifier) Send(to, subject, body string) error {\n    fmt.Printf("[SMS] provider: %s to: %s message: %s\\n", n.Provider, to, body)\n    return nil\n}\n\ntype PushNotifier struct{ AppID string }\nfunc (n *PushNotifier) Send(to, subject, body string) error {\n    fmt.Printf("[PUSH] app: %s device: %s title: %s\\n  body: %s\\n", n.AppID, to, subject, body)\n    return nil\n}\n\ntype StdoutNotifier struct{}\nfunc (n *StdoutNotifier) Send(to, subject, body string) error {\n    fmt.Printf("[STDOUT] to: %s | %s: %s\\n", to, subject, body)\n    return nil\n}\n\nfunc NewNotifier(notifierType string) (Notifier, error) {\n    switch strings.ToLower(notifierType) {\n    case "email":\n        return &EmailNotifier{From: "noreply@example.com"}, nil\n    case "sms":\n        return &SMSNotifier{Provider: "twilio"}, nil\n    case "push":\n        return &PushNotifier{AppID: "com.example.app"}, nil\n    default:\n        return nil, fmt.Errorf("неизвестный тип: %s", notifierType)\n    }\n}\n\ntype StdoutLogger struct{}\nfunc (l *StdoutLogger) Log(level, message string) {\n    fmt.Printf("[%s] %s\\n", level, message)\n}\n\ntype FileLogger struct{ Filename string }\nfunc (l *FileLogger) Log(level, message string) {\n    fmt.Printf("[FILE:%s] [%s] %s\\n", l.Filename, level, message)\n}\n\ntype NotificationFactory interface {\n    CreateNotifier() Notifier\n    CreateLogger() Logger\n}\n\ntype DevelopmentFactory struct{}\nfunc (f *DevelopmentFactory) CreateNotifier() Notifier { return &StdoutNotifier{} }\nfunc (f *DevelopmentFactory) CreateLogger() Logger     { return &StdoutLogger{} }\n\ntype ProductionFactory struct{}\nfunc (f *ProductionFactory) CreateNotifier() Notifier {\n    return &EmailNotifier{From: "noreply@prod.com"}\n}\nfunc (f *ProductionFactory) CreateLogger() Logger {\n    return &FileLogger{Filename: "/var/log/app.log"}\n}\n\nfunc sendWithFactory(factory NotificationFactory, to, subject, body string) {\n    notifier := factory.CreateNotifier()\n    logger := factory.CreateLogger()\n    if err := notifier.Send(to, subject, body); err != nil {\n        logger.Log("ERROR", err.Error())\n        return\n    }\n    logger.Log("INFO", fmt.Sprintf("уведомление отправлено для %s", to))\n}\n\nfunc main() {\n    for _, t := range []string{"email", "sms", "push"} {\n        n, err := NewNotifier(t)\n        if err != nil {\n            fmt.Println("Ошибка:", err)\n            continue\n        }\n        switch t {\n        case "email":\n            n.Send("alice@example.com", "Привет", "Как дела?")\n        case "sms":\n            n.Send("+77001234567", "OTP", "Код: 1234")\n        case "push":\n            n.Send("device123", "Уведомление", "У вас новое сообщение")\n        }\n    }\n    fmt.Println("\\nDevelopment Factory: отправка в stdout")\n    sendWithFactory(&DevelopmentFactory{}, "user@test.com", "Test", "Hello")\n    fmt.Println("\\nProduction Factory: отправка через внешние сервисы")\n    sendWithFactory(&ProductionFactory{}, "user@prod.com", "Welcome", "Welcome to production!")\n}',
      explanation: 'Factory Method инкапсулирует логику выбора конкретной реализации. Клиентский код работает с интерфейсом Notifier, не зная деталей реализации. Abstract Factory создаёт семейства связанных объектов (Notifier + Logger), гарантируя их совместимость. DevelopmentFactory возвращает простые реализации для разработки, ProductionFactory — реальные.'
    },
    {
      id: 3,
      title: 'Builder (Строитель)',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй паттерн Builder для создания сложных HTTP запросов и объектов конфигурации сервера.',
      requirements: [
        'RequestBuilder: Method, URL, Headers map, QueryParams map, Body, Timeout',
        'Fluent interface: каждый метод возвращает *RequestBuilder',
        'Метод Build() (*http.Request, error) — создаёт реальный http.Request',
        'ServerConfigBuilder: Host, Port, TLS, ReadTimeout, WriteTimeout, MaxConns, Middleware []string',
        'Метод Build() ServerConfig — с валидацией (Port 1-65535, Host не пустой)'
      ],
      expectedOutput: 'Request: POST https://api.example.com/users?page=1&limit=10\nHeaders: Content-Type=application/json X-API-Key=secret\nServerConfig: host=api.example.com port=8443 tls=true maxConns=1000',
      hint: 'Fluent interface: методы SetMethod, WithHeader, WithQuery... возвращают *RequestBuilder (return b). Build валидирует и создаёт финальный объект. Это позволяет писать цепочки: builder.SetURL(...).WithHeader(...).Build().',
      solution: 'package main\n\nimport (\n    "bytes"\n    "encoding/json"\n    "fmt"\n    "net/http"\n    "net/url"\n    "time"\n)\n\ntype RequestBuilder struct {\n    method      string\n    rawURL      string\n    headers     map[string]string\n    queryParams map[string]string\n    body        interface{}\n    timeout     time.Duration\n}\n\nfunc NewRequestBuilder() *RequestBuilder {\n    return &RequestBuilder{\n        method:      "GET",\n        headers:     make(map[string]string),\n        queryParams: make(map[string]string),\n    }\n}\n\nfunc (b *RequestBuilder) Method(method string) *RequestBuilder {\n    b.method = method\n    return b\n}\n\nfunc (b *RequestBuilder) URL(rawURL string) *RequestBuilder {\n    b.rawURL = rawURL\n    return b\n}\n\nfunc (b *RequestBuilder) Header(key, value string) *RequestBuilder {\n    b.headers[key] = value\n    return b\n}\n\nfunc (b *RequestBuilder) Query(key, value string) *RequestBuilder {\n    b.queryParams[key] = value\n    return b\n}\n\nfunc (b *RequestBuilder) Body(body interface{}) *RequestBuilder {\n    b.body = body\n    return b\n}\n\nfunc (b *RequestBuilder) Timeout(d time.Duration) *RequestBuilder {\n    b.timeout = d\n    return b\n}\n\nfunc (b *RequestBuilder) Build() (*http.Request, error) {\n    if b.rawURL == "" {\n        return nil, fmt.Errorf("URL обязателен")\n    }\n    u, err := url.Parse(b.rawURL)\n    if err != nil {\n        return nil, err\n    }\n    if len(b.queryParams) > 0 {\n        q := u.Query()\n        for k, v := range b.queryParams {\n            q.Set(k, v)\n        }\n        u.RawQuery = q.Encode()\n    }\n    var bodyReader *bytes.Reader\n    if b.body != nil {\n        data, err := json.Marshal(b.body)\n        if err != nil {\n            return nil, err\n        }\n        bodyReader = bytes.NewReader(data)\n        b.headers["Content-Type"] = "application/json"\n    }\n    var req *http.Request\n    if bodyReader != nil {\n        req, err = http.NewRequest(b.method, u.String(), bodyReader)\n    } else {\n        req, err = http.NewRequest(b.method, u.String(), nil)\n    }\n    if err != nil {\n        return nil, err\n    }\n    for k, v := range b.headers {\n        req.Header.Set(k, v)\n    }\n    return req, nil\n}\n\ntype ServerConfig struct {\n    Host         string\n    Port         int\n    TLS          bool\n    ReadTimeout  time.Duration\n    WriteTimeout time.Duration\n    MaxConns     int\n    Middleware   []string\n}\n\ntype ServerConfigBuilder struct {\n    config ServerConfig\n    errors []string\n}\n\nfunc NewServerConfigBuilder() *ServerConfigBuilder {\n    return &ServerConfigBuilder{\n        config: ServerConfig{\n            Host:         "localhost",\n            Port:         8080,\n            ReadTimeout:  30 * time.Second,\n            WriteTimeout: 30 * time.Second,\n            MaxConns:     100,\n        },\n    }\n}\n\nfunc (b *ServerConfigBuilder) Host(host string) *ServerConfigBuilder {\n    if host == "" {\n        b.errors = append(b.errors, "host не может быть пустым")\n    }\n    b.config.Host = host\n    return b\n}\n\nfunc (b *ServerConfigBuilder) Port(port int) *ServerConfigBuilder {\n    if port < 1 || port > 65535 {\n        b.errors = append(b.errors, fmt.Sprintf("порт %d некорректен", port))\n    }\n    b.config.Port = port\n    return b\n}\n\nfunc (b *ServerConfigBuilder) WithTLS() *ServerConfigBuilder {\n    b.config.TLS = true\n    return b\n}\n\nfunc (b *ServerConfigBuilder) MaxConnections(n int) *ServerConfigBuilder {\n    b.config.MaxConns = n\n    return b\n}\n\nfunc (b *ServerConfigBuilder) AddMiddleware(name string) *ServerConfigBuilder {\n    b.config.Middleware = append(b.config.Middleware, name)\n    return b\n}\n\nfunc (b *ServerConfigBuilder) Build() (ServerConfig, error) {\n    if len(b.errors) > 0 {\n        return ServerConfig{}, fmt.Errorf("ошибки конфигурации: %v", b.errors)\n    }\n    return b.config, nil\n}\n\nfunc main() {\n    req, err := NewRequestBuilder().\n        Method("POST").\n        URL("https://api.example.com/users").\n        Header("X-API-Key", "secret").\n        Query("page", "1").\n        Query("limit", "10").\n        Body(map[string]string{"name": "Alice"}).\n        Timeout(30 * time.Second).\n        Build()\n    if err != nil {\n        fmt.Println("Ошибка:", err)\n        return\n    }\n    fmt.Printf("Request: %s %s\\n", req.Method, req.URL)\n    fmt.Printf("Headers: Content-Type=%s X-API-Key=%s\\n",\n        req.Header.Get("Content-Type"), req.Header.Get("X-API-Key"))\n    cfg, err := NewServerConfigBuilder().\n        Host("api.example.com").\n        Port(8443).\n        WithTLS().\n        MaxConnections(1000).\n        AddMiddleware("logging").\n        AddMiddleware("ratelimit").\n        Build()\n    if err != nil {\n        fmt.Println("Ошибка конфига:", err)\n        return\n    }\n    fmt.Printf("ServerConfig: host=%s port=%d tls=%v maxConns=%d\\n",\n        cfg.Host, cfg.Port, cfg.TLS, cfg.MaxConns)\n}',
      explanation: 'Builder отделяет конструирование сложного объекта от его представления. Fluent interface (method chaining) делает код читаемым — шаги построения выглядят как декларативное описание. Паттерн особенно полезен когда объект имеет много опциональных параметров (альтернатива телескопическим конструкторам). Валидация в Build() гарантирует корректность объекта.'
    },
    {
      id: 4,
      title: 'Observer (Наблюдатель)',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй паттерн Observer для системы событий: подписка на события, отписка и асинхронное уведомление наблюдателей.',
      requirements: [
        'Интерфейс Observer: OnEvent(event Event)',
        'Структура Event: Type string, Data interface{}, Timestamp time.Time',
        'EventBus с методами: Subscribe(eventType string, observer Observer) func(), Publish(event Event), PublishAsync(event Event)',
        'Subscribe возвращает функцию отписки (unsubscribe)',
        'PublishAsync уведомляет наблюдателей в горутинах',
        'Защита от паники в наблюдателях: recover в горутинах'
      ],
      expectedOutput: 'UserCreated: получен LogObserver\nUserCreated: получен EmailObserver\nOrderPlaced: получен LogObserver\nОтписка EmailObserver от UserCreated\nUserUpdated: только LogObserver получил',
      hint: 'EventBus хранит map[string][]Observer. Subscribe: добавляй observer и возвращай closure с отписчиком. PublishAsync: for _, obs := range observers { go obs.OnEvent(event) }. defer recover() в горутине для защиты.',
      solution: 'package main\n\nimport (\n    "fmt"\n    "sync"\n    "time"\n)\n\ntype Event struct {\n    Type      string\n    Data      interface{}\n    Timestamp time.Time\n}\n\ntype Observer interface {\n    OnEvent(event Event)\n}\n\ntype EventBus struct {\n    mu        sync.RWMutex\n    observers map[string][]Observer\n}\n\nfunc NewEventBus() *EventBus {\n    return &EventBus{observers: make(map[string][]Observer)}\n}\n\nfunc (eb *EventBus) Subscribe(eventType string, observer Observer) func() {\n    eb.mu.Lock()\n    defer eb.mu.Unlock()\n    eb.observers[eventType] = append(eb.observers[eventType], observer)\n    return func() {\n        eb.mu.Lock()\n        defer eb.mu.Unlock()\n        observers := eb.observers[eventType]\n        for i, o := range observers {\n            if o == observer {\n                eb.observers[eventType] = append(observers[:i], observers[i+1:]...)\n                break\n            }\n        }\n    }\n}\n\nfunc (eb *EventBus) Publish(event Event) {\n    eb.mu.RLock()\n    observers := make([]Observer, len(eb.observers[event.Type]))\n    copy(observers, eb.observers[event.Type])\n    eb.mu.RUnlock()\n    for _, obs := range observers {\n        obs.OnEvent(event)\n    }\n}\n\nfunc (eb *EventBus) PublishAsync(event Event) {\n    eb.mu.RLock()\n    observers := make([]Observer, len(eb.observers[event.Type]))\n    copy(observers, eb.observers[event.Type])\n    eb.mu.RUnlock()\n    var wg sync.WaitGroup\n    for _, obs := range observers {\n        wg.Add(1)\n        go func(o Observer) {\n            defer wg.Done()\n            defer func() {\n                if r := recover(); r != nil {\n                    fmt.Printf("Паника в наблюдателе: %v\\n", r)\n                }\n            }()\n            o.OnEvent(event)\n        }(obs)\n    }\n    wg.Wait()\n}\n\ntype LogObserver struct{ Name string }\nfunc (o *LogObserver) OnEvent(event Event) {\n    fmt.Printf("[LOG:%s] %s: %v\\n", o.Name, event.Type, event.Data)\n}\n\ntype EmailObserver struct{ Email string }\nfunc (o *EmailObserver) OnEvent(event Event) {\n    fmt.Printf("[EMAIL:%s] Событие %s: %v\\n", o.Email, event.Type, event.Data)\n}\n\nfunc main() {\n    bus := NewEventBus()\n    logger := &LogObserver{Name: "main"}\n    emailer := &EmailObserver{Email: "admin@example.com"}\n    bus.Subscribe("UserCreated", logger)\n    unsubEmail := bus.Subscribe("UserCreated", emailer)\n    bus.Subscribe("OrderPlaced", logger)\n    bus.Publish(Event{Type: "UserCreated", Data: map[string]string{"name": "Alice"}, Timestamp: time.Now()})\n    bus.Publish(Event{Type: "OrderPlaced", Data: map[string]int{"order_id": 123}, Timestamp: time.Now()})\n    fmt.Println("Отписка EmailObserver от UserCreated")\n    unsubEmail()\n    bus.Publish(Event{Type: "UserCreated", Data: map[string]string{"name": "Bob"}, Timestamp: time.Now()})\n}',
      explanation: 'EventBus с map[string][]Observer обеспечивает типизированные события. Subscribe возвращает closure для отписки — идиоматичный Go паттерн. Копирование среза observers под RLock перед вызовами предотвращает deadlock при рекурсивных событиях. PublishAsync с recover в горутинах: паника в одном наблюдателе не убивает всю систему.'
    },
    {
      id: 5,
      title: 'Strategy (Стратегия)',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй паттерн Strategy для системы сортировки, сжатия данных и алгоритмов маршрутизации.',
      requirements: [
        'Интерфейс SortStrategy: Sort(data []int) []int',
        'Реализации: BubbleSortStrategy, QuickSortStrategy, MergeSortStrategy',
        'Структура Sorter с методом SetStrategy и Sort',
        'Интерфейс CompressionStrategy: Compress(data []byte) []byte, Decompress(data []byte) []byte',
        'Реализации: NoCompression, RLECompression (простое RLE)',
        'Контекст может менять стратегию в runtime'
      ],
      expectedOutput: 'BubbleSort: [1 2 3 5 8]\nQuickSort: [1 2 3 5 8]\nMergeSort: [1 2 3 5 8]\nRLE compress: AAABBBCC -> A3B3C2 (экономия байт)\nNoCompression: без изменений',
      hint: 'Strategy — инкапсуляция алгоритма за интерфейсом. Sorter.SetStrategy(s SortStrategy) меняет алгоритм. Для RLE: пробегай по байтам, считай последовательные одинаковые, записывай байт+счётчик.',
      solution: 'package main\n\nimport (\n    "fmt"\n    "sort"\n)\n\ntype SortStrategy interface {\n    Sort(data []int) []int\n    Name() string\n}\n\ntype BubbleSortStrategy struct{}\nfunc (s *BubbleSortStrategy) Name() string { return "BubbleSort" }\nfunc (s *BubbleSortStrategy) Sort(data []int) []int {\n    result := make([]int, len(data))\n    copy(result, data)\n    n := len(result)\n    for i := 0; i < n-1; i++ {\n        for j := 0; j < n-i-1; j++ {\n            if result[j] > result[j+1] {\n                result[j], result[j+1] = result[j+1], result[j]\n            }\n        }\n    }\n    return result\n}\n\ntype QuickSortStrategy struct{}\nfunc (s *QuickSortStrategy) Name() string { return "QuickSort" }\nfunc (s *QuickSortStrategy) Sort(data []int) []int {\n    result := make([]int, len(data))\n    copy(result, data)\n    sort.Ints(result)\n    return result\n}\n\ntype MergeSortStrategy struct{}\nfunc (s *MergeSortStrategy) Name() string { return "MergeSort" }\nfunc (s *MergeSortStrategy) Sort(data []int) []int {\n    if len(data) <= 1 {\n        return data\n    }\n    result := make([]int, len(data))\n    copy(result, data)\n    mid := len(result) / 2\n    left := s.Sort(result[:mid])\n    right := s.Sort(result[mid:])\n    merged := make([]int, 0, len(result))\n    i, j := 0, 0\n    for i < len(left) && j < len(right) {\n        if left[i] <= right[j] {\n            merged = append(merged, left[i]); i++\n        } else {\n            merged = append(merged, right[j]); j++\n        }\n    }\n    merged = append(merged, left[i:]...)\n    merged = append(merged, right[j:]...)\n    return merged\n}\n\ntype Sorter struct {\n    strategy SortStrategy\n}\nfunc (s *Sorter) SetStrategy(strategy SortStrategy) { s.strategy = strategy }\nfunc (s *Sorter) Sort(data []int) []int {\n    if s.strategy == nil {\n        return data\n    }\n    return s.strategy.Sort(data)\n}\n\ntype CompressionStrategy interface {\n    Compress(data []byte) []byte\n    Decompress(data []byte) []byte\n    Name() string\n}\n\ntype NoCompression struct{}\nfunc (c *NoCompression) Name() string                     { return "NoCompression" }\nfunc (c *NoCompression) Compress(data []byte) []byte   { return data }\nfunc (c *NoCompression) Decompress(data []byte) []byte { return data }\n\ntype RLECompression struct{}\nfunc (c *RLECompression) Name() string { return "RLE" }\nfunc (c *RLECompression) Compress(data []byte) []byte {\n    if len(data) == 0 {\n        return nil\n    }\n    var result []byte\n    count := 1\n    for i := 1; i <= len(data); i++ {\n        if i < len(data) && data[i] == data[i-1] && count < 255 {\n            count++\n        } else {\n            result = append(result, data[i-1], byte(count))\n            count = 1\n        }\n    }\n    return result\n}\nfunc (c *RLECompression) Decompress(data []byte) []byte {\n    var result []byte\n    for i := 0; i+1 < len(data); i += 2 {\n        for j := 0; j < int(data[i+1]); j++ {\n            result = append(result, data[i])\n        }\n    }\n    return result\n}\n\nfunc main() {\n    data := []int{5, 3, 8, 1, 2}\n    sorter := &Sorter{}\n    for _, s := range []SortStrategy{&BubbleSortStrategy{}, &QuickSortStrategy{}, &MergeSortStrategy{}} {\n        sorter.SetStrategy(s)\n        fmt.Printf("%s: %v\\n", s.Name(), sorter.Sort(data))\n    }\n    input := []byte("AAABBBCC")\n    rle := &RLECompression{}\n    compressed := rle.Compress(input)\n    decompressed := rle.Decompress(compressed)\n    fmt.Printf("\\nRLE: %s -> compressed: %d bytes (was %d)\\n", input, len(compressed), len(input))\n    fmt.Printf("Decompress: %s\\n", decompressed)\n    noComp := &NoCompression{}\n    fmt.Printf("NoCompression: %d bytes -> %d bytes\\n", len(input), len(noComp.Compress(input)))\n}',
      explanation: 'Strategy делает алгоритмы взаимозаменяемыми. Sorter работает с любой SortStrategy через интерфейс — добавление новой сортировки не изменяет код Sorter. В Go стратегии часто передаются как функции (func([]int) []int), что ещё лаконичнее. RLE compression демонстрирует нетривиальную стратегию: каждый уникальный алгоритм сжатия может быть стратегией.'
    },
    {
      id: 6,
      title: 'Decorator (Декоратор)',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй паттерн Decorator для добавления функциональности к HTTP обработчикам и к операциям с хранилищем данных.',
      requirements: [
        'Тип HandlerFunc = func(http.ResponseWriter, *http.Request)',
        'Декораторы-middleware: WithLogging, WithAuth(token string), WithRateLimit(rps int), WithRecovery',
        'Функция Chain(handler HandlerFunc, middlewares ...Middleware) HandlerFunc — цепочка декораторов',
        'Интерфейс DataStore: Get(key string) (string, error), Set(key, value string) error',
        'Декораторы: WithCache(store DataStore, ttl), WithRetry(store DataStore, attempts), WithMetrics(store DataStore)'
      ],
      expectedOutput: 'GET /api/data (без токена): 401 Unauthorized\nGET /api/data (с токеном): 200 OK (заняло 1ms)\nWithCache: второй запрос из кэша (0ms)\nWithRetry: успешно с 3-й попытки',
      hint: 'Middleware = func(HandlerFunc) HandlerFunc. Chain применяет middleware в обратном порядке: последний middleware в списке будет ближайшим к обработчику. DataStore декораторы оборачивают другой DataStore и добавляют поведение.',
      solution: 'package main\n\nimport (\n    "fmt"\n    "net/http"\n    "net/http/httptest"\n    "sync"\n    "time"\n)\n\ntype HandlerFunc func(http.ResponseWriter, *http.Request)\ntype Middleware func(HandlerFunc) HandlerFunc\n\nfunc WithLogging(next HandlerFunc) HandlerFunc {\n    return func(w http.ResponseWriter, r *http.Request) {\n        start := time.Now()\n        rec := httptest.NewRecorder()\n        next(rec, r)\n        for k, v := range rec.Header() {\n            w.Header()[k] = v\n        }\n        w.WriteHeader(rec.Code)\n        w.Write(rec.Body.Bytes())\n        fmt.Printf("[LOG] %s %s -> %d (%v)\\n", r.Method, r.URL.Path, rec.Code, time.Since(start))\n    }\n}\n\nfunc WithAuth(token string) Middleware {\n    return func(next HandlerFunc) HandlerFunc {\n        return func(w http.ResponseWriter, r *http.Request) {\n            if r.Header.Get("X-Token") != token {\n                http.Error(w, "Unauthorized", http.StatusUnauthorized)\n                return\n            }\n            next(w, r)\n        }\n    }\n}\n\nfunc WithRecovery(next HandlerFunc) HandlerFunc {\n    return func(w http.ResponseWriter, r *http.Request) {\n        defer func() {\n            if err := recover(); err != nil {\n                http.Error(w, "Internal Server Error", 500)\n                fmt.Printf("[PANIC] %v\\n", err)\n            }\n        }()\n        next(w, r)\n    }\n}\n\nfunc Chain(handler HandlerFunc, middlewares ...Middleware) HandlerFunc {\n    for i := len(middlewares) - 1; i >= 0; i-- {\n        handler = middlewares[i](handler)\n    }\n    return handler\n}\n\ntype DataStore interface {\n    Get(key string) (string, error)\n    Set(key, value string) error\n}\n\ntype MemStore struct {\n    mu   sync.RWMutex\n    data map[string]string\n}\nfunc NewMemStore() *MemStore { return &MemStore{data: make(map[string]string)} }\nfunc (s *MemStore) Get(key string) (string, error) {\n    s.mu.RLock()\n    defer s.mu.RUnlock()\n    v, ok := s.data[key]\n    if !ok { return "", fmt.Errorf("не найден: %s", key) }\n    return v, nil\n}\nfunc (s *MemStore) Set(key, value string) error {\n    s.mu.Lock()\n    defer s.mu.Unlock()\n    s.data[key] = value\n    return nil\n}\n\ntype CacheDecorator struct {\n    store  DataStore\n    cache  map[string]string\n    mu     sync.RWMutex\n}\nfunc WithCache(store DataStore) *CacheDecorator {\n    return &CacheDecorator{store: store, cache: make(map[string]string)}\n}\nfunc (c *CacheDecorator) Get(key string) (string, error) {\n    c.mu.RLock()\n    if v, ok := c.cache[key]; ok {\n        c.mu.RUnlock()\n        fmt.Printf("[CACHE HIT] %s\\n", key)\n        return v, nil\n    }\n    c.mu.RUnlock()\n    v, err := c.store.Get(key)\n    if err == nil {\n        c.mu.Lock()\n        c.cache[key] = v\n        c.mu.Unlock()\n    }\n    return v, err\n}\nfunc (c *CacheDecorator) Set(key, value string) error {\n    c.mu.Lock()\n    c.cache[key] = value\n    c.mu.Unlock()\n    return c.store.Set(key, value)\n}\n\ntype RetryDecorator struct {\n    store    DataStore\n    attempts int\n}\nfunc WithRetry(store DataStore, attempts int) *RetryDecorator {\n    return &RetryDecorator{store: store, attempts: attempts}\n}\nfunc (r *RetryDecorator) Get(key string) (string, error) {\n    var err error\n    for i := 0; i < r.attempts; i++ {\n        var v string\n        v, err = r.store.Get(key)\n        if err == nil {\n            return v, nil\n        }\n        fmt.Printf("[RETRY] попытка %d/%d: %v\\n", i+1, r.attempts, err)\n    }\n    return "", err\n}\nfunc (r *RetryDecorator) Set(key, value string) error { return r.store.Set(key, value) }\n\nfunc main() {\n    apiHandler := func(w http.ResponseWriter, r *http.Request) {\n        fmt.Fprintln(w, "Hello, World!")\n    }\n    protected := Chain(apiHandler, WithLogging, WithAuth("secret123"), WithRecovery)\n    req1, _ := http.NewRequest("GET", "/api/data", nil)\n    w1 := httptest.NewRecorder()\n    protected(w1, req1)\n    fmt.Printf("Без токена: %d\\n", w1.Code)\n    req2, _ := http.NewRequest("GET", "/api/data", nil)\n    req2.Header.Set("X-Token", "secret123")\n    w2 := httptest.NewRecorder()\n    protected(w2, req2)\n    fmt.Printf("С токеном: %d\\n", w2.Code)\n    base := NewMemStore()\n    base.Set("key1", "value1")\n    cached := WithCache(base)\n    v, _ := cached.Get("key1")\n    fmt.Printf("\\nПервый Get: %s\\n", v)\n    v, _ = cached.Get("key1")\n    fmt.Printf("Второй Get: %s (из кэша)\\n", v)\n}',
      explanation: 'Decorator оборачивает объект, добавляя поведение без изменения интерфейса. Для HTTP middleware: паттерн func(HandlerFunc) HandlerFunc. Chain применяет middleware снаружи внутрь (обратный порядок). DataStore декораторы: каждый оборачивает следующий и добавляет одну ответственность (cache, retry, metrics) — Single Responsibility Principle.'
    },
    {
      id: 7,
      title: 'Adapter (Адаптер)',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй паттерн Adapter для совместимости разных интерфейсов: адаптация сторонних библиотек и конвертация форматов данных.',
      requirements: [
        'Целевой интерфейс Logger: Log(level, msg string)',
        'Адаптируемый legacyLogger: WriteLog(timestamp, severity, message string)',
        'LegacyLoggerAdapter обёртывает legacyLogger и реализует Logger',
        'Целевой интерфейс PaymentGateway: Charge(amount float64, currency, description string) error',
        'Адаптируй две разные платёжные системы (разные API) под общий интерфейс',
        'Адаптер для конвертации метрических систем: TemperatureAdapter (Celsius <-> Fahrenheit)'
      ],
      expectedOutput: 'LegacyAdapter.Log("ERROR","DB down") -> WriteLog(timestamp,"SEVERE","DB down")\nStripeAdapter.Charge(100, "USD", "Order") -> stripe.CreateCharge({amount:10000,...})\nPayPalAdapter.Charge(100, "USD", "Order") -> paypal.MakePayment({value:"100.00",...})\nTemperature 100°C = 212°F',
      hint: 'Adapter: новая структура содержит поле с адаптируемым объектом и реализует целевой интерфейс, транслируя вызовы. Часто адаптер просто конвертирует параметры и делегирует вызов.',
      solution: 'package main\n\nimport (\n    "fmt"\n    "time"\n)\n\n// ===== Logger Adapter =====\ntype Logger interface {\n    Log(level, msg string)\n}\n\ntype LegacyLogger struct{}\nfunc (l *LegacyLogger) WriteLog(timestamp, severity, message string) {\n    fmt.Printf("[LEGACY] %s | %s | %s\\n", timestamp, severity, message)\n}\n\ntype LegacyLoggerAdapter struct {\n    legacy *LegacyLogger\n}\nfunc NewLegacyLoggerAdapter(l *LegacyLogger) *LegacyLoggerAdapter {\n    return &LegacyLoggerAdapter{legacy: l}\n}\nfunc (a *LegacyLoggerAdapter) Log(level, msg string) {\n    severityMap := map[string]string{\n        "DEBUG": "FINE", "INFO": "INFO", "WARN": "WARNING", "ERROR": "SEVERE",\n    }\n    severity := severityMap[level]\n    if severity == "" {\n        severity = level\n    }\n    a.legacy.WriteLog(time.Now().Format("2006-01-02 15:04:05"), severity, msg)\n}\n\n// ===== Payment Adapter =====\ntype PaymentGateway interface {\n    Charge(amount float64, currency, description string) error\n}\n\ntype StripeAPI struct{}\nfunc (s *StripeAPI) CreateCharge(amountCents int, currency, desc string) error {\n    fmt.Printf("[STRIPE] CreateCharge: amount=%d cents, currency=%s, desc=%s\\n", amountCents, currency, desc)\n    return nil\n}\n\ntype PayPalAPI struct{}\nfunc (p *PayPalAPI) MakePayment(value, currency, note string) error {\n    fmt.Printf("[PAYPAL] MakePayment: value=%s, currency=%s, note=%s\\n", value, currency, note)\n    return nil\n}\n\ntype StripeAdapter struct{ stripe *StripeAPI }\nfunc (a *StripeAdapter) Charge(amount float64, currency, description string) error {\n    return a.stripe.CreateCharge(int(amount*100), currency, description)\n}\n\ntype PayPalAdapter struct{ paypal *PayPalAPI }\nfunc (a *PayPalAdapter) Charge(amount float64, currency, description string) error {\n    return a.paypal.MakePayment(fmt.Sprintf("%.2f", amount), currency, description)\n}\n\n// ===== Temperature Adapter =====\ntype CelsiusThermometer struct{ temperature float64 }\nfunc (t *CelsiusThermometer) GetCelsius() float64 { return t.temperature }\n\ntype FahrenheitReader interface {\n    GetFahrenheit() float64\n}\n\ntype CelsiusToFahrenheitAdapter struct {\n    celsius *CelsiusThermometer\n}\nfunc (a *CelsiusToFahrenheitAdapter) GetFahrenheit() float64 {\n    return a.celsius.GetCelsius()*9/5 + 32\n}\n\nfunc processPayment(gw PaymentGateway, amount float64) {\n    if err := gw.Charge(amount, "USD", "Тестовый заказ"); err != nil {\n        fmt.Println("Ошибка:", err)\n    }\n}\n\nfunc main() {\n    legacy := &LegacyLogger{}\n    adapter := NewLegacyLoggerAdapter(legacy)\n    var logger Logger = adapter\n    logger.Log("ERROR", "DB down")\n    logger.Log("INFO", "Сервер запущен")\n    fmt.Println()\n    var gw PaymentGateway\n    gw = &StripeAdapter{stripe: &StripeAPI{}}\n    processPayment(gw, 100)\n    gw = &PayPalAdapter{paypal: &PayPalAPI{}}\n    processPayment(gw, 100)\n    fmt.Println()\n    thermo := &CelsiusThermometer{temperature: 100}\n    var reader FahrenheitReader = &CelsiusToFahrenheitAdapter{celsius: thermo}\n    fmt.Printf("Temperature %.0f°C = %.0f°F\\n", thermo.GetCelsius(), reader.GetFahrenheit())\n}',
      explanation: 'Adapter позволяет использовать несовместимые интерфейсы вместе. LegacyLoggerAdapter транслирует уровни и форматирует timestamp. StripeAdapter конвертирует float64 в центы (умножение на 100), PayPalAdapter форматирует как строку — каждый делает то, что нужно конкретному API. Клиентский код (processPayment) работает только с PaymentGateway и не знает о Stripe или PayPal.'
    },
    {
      id: 8,
      title: 'Command (Команда)',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй паттерн Command с историей команд, отменой (undo) и повтором (redo) для текстового редактора.',
      requirements: [
        'Интерфейс Command: Execute() error, Undo() error, Description() string',
        'Текстовый редактор: Document struct с полем Text',
        'Команды: InsertCommand, DeleteCommand, ReplaceCommand',
        'CommandHistory: стек выполненных команд и стек отменённых (для redo)',
        'Методы истории: Execute(cmd), Undo() error, Redo() error, History() []string',
        'Макро-команда: MacroCommand объединяет несколько команд в одну (атомарная)'
      ],
      expectedOutput: 'Документ: "Привет, Мир!"\nUndo: "Привет, "\nUndo: ""\nRedo: "Привет, "\nHistory: [Insert "Привет, " | Delete 7 символов | Insert "Мир!"]',
      hint: 'CommandHistory хранит два стека: []Command для done и []Command для undone. Execute: добавляй в done, очищай undone (новое действие ломает redo-историю). Undo: pop из done, вызывай Undo(), push в undone.',
      solution: 'package main\n\nimport (\n    "fmt"\n    "strings"\n)\n\ntype Command interface {\n    Execute() error\n    Undo() error\n    Description() string\n}\n\ntype Document struct {\n    Text string\n}\n\nfunc (d *Document) String() string { return d.Text }\n\ntype InsertCommand struct {\n    doc      *Document\n    position int\n    text     string\n}\nfunc (c *InsertCommand) Execute() error {\n    if c.position > len(c.doc.Text) {\n        c.position = len(c.doc.Text)\n    }\n    c.doc.Text = c.doc.Text[:c.position] + c.text + c.doc.Text[c.position:]\n    return nil\n}\nfunc (c *InsertCommand) Undo() error {\n    c.doc.Text = c.doc.Text[:c.position] + c.doc.Text[c.position+len(c.text):]\n    return nil\n}\nfunc (c *InsertCommand) Description() string {\n    return fmt.Sprintf("Insert %q на позиции %d", c.text, c.position)\n}\n\ntype DeleteCommand struct {\n    doc      *Document\n    position int\n    length   int\n    deleted  string\n}\nfunc (c *DeleteCommand) Execute() error {\n    end := c.position + c.length\n    if end > len(c.doc.Text) {\n        end = len(c.doc.Text)\n    }\n    c.deleted = c.doc.Text[c.position:end]\n    c.doc.Text = c.doc.Text[:c.position] + c.doc.Text[end:]\n    return nil\n}\nfunc (c *DeleteCommand) Undo() error {\n    c.doc.Text = c.doc.Text[:c.position] + c.deleted + c.doc.Text[c.position:]\n    return nil\n}\nfunc (c *DeleteCommand) Description() string {\n    return fmt.Sprintf("Delete %d символов на позиции %d", c.length, c.position)\n}\n\ntype MacroCommand struct {\n    commands    []Command\n    description string\n}\nfunc (m *MacroCommand) Execute() error {\n    for _, cmd := range m.commands {\n        if err := cmd.Execute(); err != nil {\n            return err\n        }\n    }\n    return nil\n}\nfunc (m *MacroCommand) Undo() error {\n    for i := len(m.commands) - 1; i >= 0; i-- {\n        if err := m.commands[i].Undo(); err != nil {\n            return err\n        }\n    }\n    return nil\n}\nfunc (m *MacroCommand) Description() string { return m.description }\n\ntype CommandHistory struct {\n    done   []Command\n    undone []Command\n}\n\nfunc (h *CommandHistory) Execute(cmd Command) error {\n    if err := cmd.Execute(); err != nil {\n        return err\n    }\n    h.done = append(h.done, cmd)\n    h.undone = nil\n    return nil\n}\n\nfunc (h *CommandHistory) Undo() error {\n    if len(h.done) == 0 {\n        return fmt.Errorf("нечего отменять")\n    }\n    cmd := h.done[len(h.done)-1]\n    h.done = h.done[:len(h.done)-1]\n    if err := cmd.Undo(); err != nil {\n        return err\n    }\n    h.undone = append(h.undone, cmd)\n    return nil\n}\n\nfunc (h *CommandHistory) Redo() error {\n    if len(h.undone) == 0 {\n        return fmt.Errorf("нечего повторять")\n    }\n    cmd := h.undone[len(h.undone)-1]\n    h.undone = h.undone[:len(h.undone)-1]\n    if err := cmd.Execute(); err != nil {\n        return err\n    }\n    h.done = append(h.done, cmd)\n    return nil\n}\n\nfunc (h *CommandHistory) History() []string {\n    descs := make([]string, len(h.done))\n    for i, cmd := range h.done {\n        descs[i] = cmd.Description()\n    }\n    return descs\n}\n\nfunc main() {\n    doc := &Document{}\n    history := &CommandHistory{}\n    history.Execute(&InsertCommand{doc: doc, position: 0, text: "Привет, "})\n    history.Execute(&InsertCommand{doc: doc, position: len(doc.Text), text: "Мир!"})\n    fmt.Printf("Документ: %q\\n", doc.Text)\n    history.Undo()\n    fmt.Printf("После Undo: %q\\n", doc.Text)\n    history.Undo()\n    fmt.Printf("После Undo 2: %q\\n", doc.Text)\n    history.Redo()\n    fmt.Printf("После Redo: %q\\n", doc.Text)\n    history.Execute(&InsertCommand{doc: doc, position: len(doc.Text), text: " Golang!"})\n    fmt.Printf("Финальный документ: %q\\n", doc.Text)\n    fmt.Printf("История: [%s]\\n", strings.Join(history.History(), " | "))\n}',
      explanation: 'Command инкапсулирует действие и его отмену. Каждая команда хранит всё необходимое для выполнения и отмены (deleted в DeleteCommand). CommandHistory с двумя стеками: выполнение нового действия очищает redo-стек (стандартное поведение редакторов). MacroCommand агрегирует команды — Execute и Undo обеспечивают атомарность всей последовательности.'
    },
    {
      id: 9,
      title: 'Iterator (Итератор)',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй паттерн Iterator для различных структур данных: связного списка, дерева и диапазона чисел.',
      requirements: [
        'Интерфейс Iterator: HasNext() bool, Next() interface{}',
        'LinkedList с методом Iterator() Iterator',
        'BinaryTree с итераторами: InOrder(), PreOrder(), PostOrder()',
        'RangeIterator(start, end, step int) Iterator',
        'FilterIterator(iter Iterator, predicate func(interface{}) bool) Iterator — декоратор',
        'MapIterator(iter Iterator, transform func(interface{}) interface{}) Iterator — декоратор'
      ],
      expectedOutput: 'LinkedList итератор: [1 2 3 4 5]\nBinaryTree InOrder: [1 2 3 4 5 6 7]\nRange(1,10,2): [1 3 5 7 9]\nFilter чётных из Range: [2 4 6 8 10]\nMap(*2) из [1..5]: [2 4 6 8 10]',
      hint: 'Iterator хранит текущую позицию. LinkedList Iterator: current *Node. BinaryTree InOrder Iterator: используй стек для имитации рекурсии. FilterIterator: в HasNext продвигайся пока не найдёшь подходящий элемент.',
      solution: 'package main\n\nimport "fmt"\n\ntype Iterator interface {\n    HasNext() bool\n    Next() interface{}\n}\n\n// --- LinkedList ---\ntype ListNode struct {\n    val  interface{}\n    next *ListNode\n}\n\ntype LinkedList struct{ head *ListNode }\nfunc (l *LinkedList) Push(val interface{}) {\n    l.head = &ListNode{val: val, next: l.head}\n}\nfunc (l *LinkedList) Append(val interface{}) {\n    node := &ListNode{val: val}\n    if l.head == nil {\n        l.head = node\n        return\n    }\n    curr := l.head\n    for curr.next != nil {\n        curr = curr.next\n    }\n    curr.next = node\n}\n\ntype ListIterator struct{ current *ListNode }\nfunc (it *ListIterator) HasNext() bool        { return it.current != nil }\nfunc (it *ListIterator) Next() interface{} {\n    val := it.current.val\n    it.current = it.current.next\n    return val\n}\nfunc (l *LinkedList) Iterator() Iterator { return &ListIterator{current: l.head} }\n\n// --- BinaryTree InOrder ---\ntype TreeNode struct {\n    Val         int\n    Left, Right *TreeNode\n}\n\ntype InOrderIterator struct {\n    stack   []*TreeNode\n    current *TreeNode\n}\nfunc NewInOrderIterator(root *TreeNode) *InOrderIterator {\n    it := &InOrderIterator{current: root}\n    return it\n}\nfunc (it *InOrderIterator) HasNext() bool { return it.current != nil || len(it.stack) > 0 }\nfunc (it *InOrderIterator) Next() interface{} {\n    for it.current != nil {\n        it.stack = append(it.stack, it.current)\n        it.current = it.current.Left\n    }\n    top := it.stack[len(it.stack)-1]\n    it.stack = it.stack[:len(it.stack)-1]\n    it.current = top.Right\n    return top.Val\n}\n\n// --- RangeIterator ---\ntype RangeIterator struct{ current, end, step int }\nfunc NewRangeIterator(start, end, step int) *RangeIterator {\n    return &RangeIterator{current: start, end: end, step: step}\n}\nfunc (it *RangeIterator) HasNext() bool { return it.current <= it.end }\nfunc (it *RangeIterator) Next() interface{} {\n    val := it.current\n    it.current += it.step\n    return val\n}\n\n// --- FilterIterator ---\ntype FilterIterator struct {\n    iter      Iterator\n    predicate func(interface{}) bool\n    nextVal   interface{}\n    hasNext   bool\n}\nfunc NewFilterIterator(iter Iterator, predicate func(interface{}) bool) *FilterIterator {\n    fi := &FilterIterator{iter: iter, predicate: predicate}\n    fi.advance()\n    return fi\n}\nfunc (fi *FilterIterator) advance() {\n    fi.hasNext = false\n    for fi.iter.HasNext() {\n        val := fi.iter.Next()\n        if fi.predicate(val) {\n            fi.nextVal = val\n            fi.hasNext = true\n            return\n        }\n    }\n}\nfunc (fi *FilterIterator) HasNext() bool { return fi.hasNext }\nfunc (fi *FilterIterator) Next() interface{} {\n    val := fi.nextVal\n    fi.advance()\n    return val\n}\n\nfunc collectAll(it Iterator) []interface{} {\n    var result []interface{}\n    for it.HasNext() {\n        result = append(result, it.Next())\n    }\n    return result\n}\n\nfunc main() {\n    list := &LinkedList{}\n    for _, v := range []int{1, 2, 3, 4, 5} {\n        list.Append(v)\n    }\n    fmt.Printf("LinkedList итератор: %v\\n", collectAll(list.Iterator()))\n    root := &TreeNode{Val: 4,\n        Left:  &TreeNode{Val: 2, Left: &TreeNode{Val: 1}, Right: &TreeNode{Val: 3}},\n        Right: &TreeNode{Val: 6, Left: &TreeNode{Val: 5}, Right: &TreeNode{Val: 7}},\n    }\n    fmt.Printf("BinaryTree InOrder: %v\\n", collectAll(NewInOrderIterator(root)))\n    fmt.Printf("Range(1,10,2): %v\\n", collectAll(NewRangeIterator(1, 10, 2)))\n    evenFilter := NewFilterIterator(NewRangeIterator(1, 10, 1), func(v interface{}) bool {\n        return v.(int)%2 == 0\n    })\n    fmt.Printf("Filter чётных: %v\\n", collectAll(evenFilter))\n}',
      explanation: 'Iterator скрывает детали обхода структуры данных. InOrder без рекурсии: стек имитирует системный стек вызовов — идём влево до упора, затем берём вершину стека и идём вправо. FilterIterator как декоратор: оборачивает любой Iterator и добавляет фильтрацию. advance() в конструкторе и после каждого Next() предвычисляет следующий валидный элемент.'
    },
    {
      id: 10,
      title: 'Chain of Responsibility (Цепочка обязанностей)',
      type: 'practice',
      difficulty: 'medium',
      description: 'Реализуй паттерн Chain of Responsibility для системы обработки HTTP запросов, валидации и авторизации.',
      requirements: [
        'Интерфейс Handler: Handle(request *Request) *Response, SetNext(handler Handler) Handler',
        'Структуры Request: Method, Path, Headers, Body, UserRole string',
        'Структуры Response: Status int, Body string',
        'Обработчики: AuthHandler (проверка токена), RoleHandler (проверка роли), RateLimitHandler, LoggingHandler, BusinessHandler',
        'Построй цепочку: Logging -> Auth -> RateLimit -> Role -> Business',
        'Каждый обработчик либо обрабатывает сам, либо передаёт следующему'
      ],
      expectedOutput: '[LOG] GET /api/admin\n[AUTH] проверка токена... OK\n[RATE] 1/100 запросов\n[ROLE] проверка роли admin... OK\n[BUSINESS] ответ: {"data": "admin panel"}\nСтатус: 200\n\n[LOG] GET /api/admin\n[AUTH] проверка токена... FAIL -> 401',
      hint: 'SetNext сохраняет следующий обработчик и возвращает его (для цепочного построения). Базовый BaseHandler реализует SetNext и callNext. Конкретные обработчики наследуют BaseHandler и переопределяют Handle.',
      solution: 'package main\n\nimport (\n    "fmt"\n    "sync"\n    "time"\n)\n\ntype Request struct {\n    Method   string\n    Path     string\n    Headers  map[string]string\n    Body     string\n    UserRole string\n}\n\ntype Response struct {\n    Status int\n    Body   string\n}\n\ntype Handler interface {\n    Handle(req *Request) *Response\n    SetNext(handler Handler) Handler\n}\n\ntype BaseHandler struct {\n    next Handler\n}\nfunc (h *BaseHandler) SetNext(handler Handler) Handler {\n    h.next = handler\n    return handler\n}\nfunc (h *BaseHandler) callNext(req *Request) *Response {\n    if h.next != nil {\n        return h.next.Handle(req)\n    }\n    return &Response{Status: 200, Body: "OK"}\n}\n\ntype LoggingHandler struct{ BaseHandler }\nfunc (h *LoggingHandler) Handle(req *Request) *Response {\n    start := time.Now()\n    fmt.Printf("[LOG] %s %s\\n", req.Method, req.Path)\n    resp := h.callNext(req)\n    fmt.Printf("[LOG] завершено: %d (%v)\\n", resp.Status, time.Since(start))\n    return resp\n}\n\ntype AuthHandler struct {\n    BaseHandler\n    validTokens map[string]string\n}\nfunc NewAuthHandler(tokens map[string]string) *AuthHandler {\n    return &AuthHandler{validTokens: tokens}\n}\nfunc (h *AuthHandler) Handle(req *Request) *Response {\n    token := req.Headers["Authorization"]\n    role, ok := h.validTokens[token]\n    if !ok {\n        fmt.Printf("[AUTH] проверка токена... FAIL\\n")\n        return &Response{Status: 401, Body: "Unauthorized"}\n    }\n    fmt.Printf("[AUTH] проверка токена... OK (роль: %s)\\n", role)\n    req.UserRole = role\n    return h.callNext(req)\n}\n\ntype RateLimitHandler struct {\n    BaseHandler\n    mu       sync.Mutex\n    requests int\n    limit    int\n}\nfunc (h *RateLimitHandler) Handle(req *Request) *Response {\n    h.mu.Lock()\n    h.requests++\n    count := h.requests\n    h.mu.Unlock()\n    if count > h.limit {\n        fmt.Printf("[RATE] превышен лимит: %d/%d\\n", count, h.limit)\n        return &Response{Status: 429, Body: "Too Many Requests"}\n    }\n    fmt.Printf("[RATE] %d/%d запросов\\n", count, h.limit)\n    return h.callNext(req)\n}\n\ntype RoleHandler struct {\n    BaseHandler\n    requiredRole string\n}\nfunc (h *RoleHandler) Handle(req *Request) *Response {\n    if req.UserRole != h.requiredRole && req.UserRole != "admin" {\n        fmt.Printf("[ROLE] проверка роли %s... FAIL (роль: %s)\\n", h.requiredRole, req.UserRole)\n        return &Response{Status: 403, Body: "Forbidden"}\n    }\n    fmt.Printf("[ROLE] проверка роли %s... OK\\n", h.requiredRole)\n    return h.callNext(req)\n}\n\ntype BusinessHandler struct{ BaseHandler }\nfunc (h *BusinessHandler) Handle(req *Request) *Response {\n    fmt.Printf("[BUSINESS] обработка %s\\n", req.Path)\n    return &Response{Status: 200, Body: `{"data": "admin panel"}`}\n}\n\nfunc main() {\n    tokens := map[string]string{"admin-token": "admin", "user-token": "user"}\n    logging := &LoggingHandler{}\n    auth := NewAuthHandler(tokens)\n    rateLimit := &RateLimitHandler{limit: 100}\n    role := &RoleHandler{requiredRole: "admin"}\n    business := &BusinessHandler{}\n    logging.SetNext(auth).SetNext(rateLimit).SetNext(role).SetNext(business)\n    fmt.Println("=== Запрос с правами admin ===")\n    req1 := &Request{\n        Method:  "GET",\n        Path:    "/api/admin",\n        Headers: map[string]string{"Authorization": "admin-token"},\n    }\n    resp := logging.Handle(req1)\n    fmt.Printf("Статус: %d\\n", resp.Status)\n    fmt.Println("\\n=== Запрос без токена ===")\n    req2 := &Request{Method: "GET", Path: "/api/admin", Headers: map[string]string{}}\n    resp2 := logging.Handle(req2)\n    fmt.Printf("Статус: %d\\n", resp2.Status)\n}',
      explanation: 'Chain of Responsibility: каждый обработчик решает сам обработать запрос или передать дальше. SetNext возвращает следующий обработчик — это позволяет строить цепочку: a.SetNext(b).SetNext(c). BaseHandler устраняет дублирование. Цепочка Logging->Auth->RateLimit->Role->Business: каждый слой независим, легко добавлять/удалять/переставлять обработчики.'
    }
  ]
}
